调整逻辑，使反应程度影响粒子的状态转换。例如，可以引入反应速率或动态变化逻辑：
```javascript
function drawSim(){
  const n = +document.getElementById('particleCount').value;
  const r = +document.getElementById('reactionLevel').value;
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  ctx.fillStyle = '#0f172a';
  ctx.fillRect(0, 0, canvas.width, canvas.height);
  ctx.strokeStyle = '#7dd3fc';
  ctx.lineWidth = 3;
  ctx.strokeRect(40, 55, 840, 210);
  for(let i = 0; i < n; i++){
    const x = 75 + (i * 67) % 790;
    const y = 92 + Math.floor(i / 12) * 54 + (i % 2) * 10;
    ctx.beginPath();
    ctx.fillStyle = Math.random() < (r / 100) ? '#f59e0b' : '#38bdf8';
    ctx.arc(x, y, 13, 0, Math.PI * 2);
    ctx.fill();
    ctx.fillStyle = '#e0f2fe';
    ctx.font = '13px sans-serif';
    ctx.fillText(Math.random() < (r / 100) ? '新' : '原', x - 8, y + 5);
  }
  ctx.fillStyle = '#cbd5e1';
  ctx.font = '18px sans-serif';
  ctx.fillText('金属冶炼：现象—机制—证据', 70, 295);
  document.getElementById('simExplain').textContent = `当前有 ${n} 个粒子，其中约 ${Math.round(n * r / 100)} 个进入“新组合”状态。`;
}

