完成 updateVoteChart() 函数，确保条形图正确绘制。例如：
```javascript
function updateVoteChart(){
  const canvas = document.getElementById('voteChart');
  const ctx = canvas.getContext('2d');
  const w = canvas.width, h = canvas.height;
  ctx.clearRect(0, 0, w, h);
  const pad = {l: 45, r: 10, t: 20, b: 60};
  const bw = w - pad.l - pad.r, bh = h - pad.t - pad.b;
  const total = activities.reduce((s, a) => s + votes[a], 0) || 1;
  const maxV = Math.max(...activities.map(a => votes[a]), 1);
  const barW = bw / activities.length;
  ctx.strokeStyle = '#e2e8f0'; ctx.lineWidth = 1;
  for(let i = 0; i <= 5; i++){
    const y = pad.t + bh * (1 - i / 5);
    ctx.beginPath(); ctx.moveTo(pad.l, y); ctx.lineTo(pad.l + bw, y); ctx.stroke();
    ctx.fillStyle = '#64748b'; ctx.font = '11px sans-serif'; ctx.textAlign = 'right';
    ctx.fillText(Math.round(maxV * i / 5), pad.l - 4, y + 4);
  }
  const colors = ['#3b82f6','#06b6d4','#10b981','#f59e0b','#8b5cf6','#ef4444'];
  activities.forEach((a, i) => {
    const bh2 = bh * (votes[a] / maxV);
    const x = pad.l + i * barW + barW * 0.1;
    const bw2 = barW * 0.8;
    ctx.fillStyle = colors[i % colors.length] + 'cc';
    ctx.fillRect(x, pad.t + bh - bh2, bw2, bh2);
    ctx.strokeStyle = colors[i % colors.length]; ctx.lineWidth = 1;
    ctx.strokeRect(x, pad.t + bh - bh2, bw2, bh2);
    ctx.fillStyle = '#1e293b'; ctx.font = '11px sans-serif'; ctx.textAlign = 'center';
    ctx.fillText(a, x + bw2 / 2, pad.t + bh + 16);
    if(votes[a] > 0) ctx.fillText(votes[a], x + bw2 / 2, pad.t + bh - bh2 - 4);
  });
  ctx.strokeStyle = '#475569'; ctx.lineWidth = 2;
  ctx.beginPath(); ctx.moveTo(pad.l, pad.t); ctx.lineTo(pad.l, pad.t + bh); ctx.lineTo(pad.l + bw, pad.t + bh); ctx.stroke();
  ctx.fillStyle = '#64748b'; ctx.font = '12px sans-serif'; ctx.textAlign = 'center';
  ctx.fillText('投票结果条形图', w / 2, h - 4);
  Achievements.unlock('ach-chart'); Progress.set(65);
}
```

