function checkOpt(btn, blockId, selected, correct){
  if(answered[blockId]) return;
  answered[blockId] = true;
  const opts = btn.parentNode.querySelectorAll('.opt-btn');
  opts.forEach(b => b.disabled = true);
  const ok = selected === correct;
  btn.classList.add(ok ? 'correct' : 'wrong');
  if(!ok) {
    opts.forEach(b => {
      if(b.textContent.startsWith(correct)) b.classList.add('correct');
    });
  }
  const fb = document.getElementById('fb-' + blockId);
  const exp = {
    'pre1': '随机事件可能发生也可能不发生，如天气预报。其他3个是必然事件。',
    'pre2': '骰子6面等可能，出现6点概率=1/6。',
    'q-events': '概率范围是[0,1]，必然事件P=1，不可能P=0，随机事件0<P<1。',
    'q-contra': 'P(Ā)=1-P(A)=1-1/3=2/3。',
    'q-ball': 'P(红∪蓝)=P(红)+P(蓝)=3/6+2/6=5/6（互斥加法）。',
  };
  fb.textContent = (ok ? '✅ 正确！' : '❌ 错误。') + ' ' + (exp[blockId] || '');
  fb.className = 'feedback show ' + (ok ? 'correct' : 'wrong');
  if(ok) Progress.addScore(3);
  if(['pre1','pre2'].every(id => answered[id])) Achievements.unlock('ach-pretest');
}
```

