确保所有交互元素和代码逻辑仅与光的折射相关。例如，修改drawGeneric函数，使其仅处理与光的折射相关的变量和公式。可以参考以下修改：
```javascript
function drawGeneric(){
    clearCanvas();
    axes();
    const a = +document.getElementById('p1').value; // 入射角
    const b = +document.getElementById('p2').value; // 介质折射率
    const c = +document.getElementById('p3').value; // 表面类型

    // 仅处理光的折射相关逻辑
    let value = 0;
    let label = '';
    if (c === 1) { // 平面
        value = a * (1 - 1 / b);
        label = `入射角 ${a}°，折射角 ${value.toFixed(1)}°`;
    } else if (c === 2) { // 水面
        value = a * (1 - 1 / b);
        label = `入射角 ${a}°，折射角 ${value.toFixed(1)}°`;
    } else if (c === 3) { // 玻璃
        value = a * (1 - 1 / b);
        label = `入射角 ${a}°，折射角 ${value.toFixed(1)}°`;
    }

    ctx.strokeStyle = '#fbbf24';
    ctx.lineWidth = 5;
    ctx.beginPath();
    ctx.moveTo(420, 80);
    ctx.lineTo(500, 240);
    ctx.lineTo(610, 110 + value);
    ctx.stroke();

    ctx.strokeStyle = '#38bdf8';
    ctx.beginPath();
    ctx.moveTo(90, 240);
    ctx.lineTo(820, 240);
    ctx.stroke();

    text('光的折射', 80, 86, 34, '#fbbf24');
    text(label, 80, 138, 26, '#dbeafe');
    text('拖动变量后，用“现象—变量—解释”三句话说清变化原因。', 80, 405, 24, '#cbd5e1');
    document.getElementById('lab-feedback').textContent = label + '。请解释哪个变量改变导致了结果变化。';
}
```

